import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import { motion, AnimatePresence } from "framer-motion";
import { Link, useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';

const Wishlist = () => {
  const { user } = useAuth();
  const { addToCart } = useCart();
  const [wishlistItems, setWishlistItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [toast, setToast] = useState(null);
  const navigate = useNavigate();

  // Fetch wishlist items
  useEffect(() => {
    const fetchWishlist = async () => {
      try {
        const token = localStorage.getItem('token');
        if (!token) return;

        const response = await axios.get("http://localhost:3000/api/v1/wishlist", {
          headers: { 'Authorization': `Bearer ${token}` }
        });
        setWishlistItems(response.data);
      } catch (err) {
        setError(err.response?.data?.message || "Failed to load wishlist");
      } finally {
        setLoading(false);
      }
    };

    fetchWishlist();
  }, [user]);

  // Wishlist toggle handler
  const handleWishlistToggle = async (e, productId) => {
    e.stopPropagation();
    e.preventDefault();

    try {
      const token = localStorage.getItem('token');
      if (!token) {
        navigate('/login');
        return;
      }

      const existingItem = wishlistItems.find(item => item.product._id === productId);

      if (existingItem) {
        await axios.delete(`http://localhost:3000/api/v1/wishlist/${existingItem._id}`, {
          headers: { 'Authorization': `Bearer ${token}` }
        });
        setWishlistItems(prev => prev.filter(item => item._id !== existingItem._id));
        setToast({ message: "Removed from wishlist", type: "success" });
      } else {
        const response = await axios.post(
          "http://localhost:3000/api/v1/wishlist",
          { productId },
          { headers: { 'Authorization': `Bearer ${token}` } }
        );
        setWishlistItems(prev => [...prev, response.data]);
        setToast({ message: "Added to wishlist", type: "success" });
      }
    } catch (err) {
      setToast({ 
        message: err.response?.data?.message || "Wishlist update failed",
        type: "error"
      });
    }
  };

  // Add to cart handler
  const handleAddToCart = async (e, product) => {
    e.stopPropagation();
    const result = await addToCart(product);
    setToast({
      message: result.success ? "Added to cart" : "Failed to add to cart",
      type: result.success ? "success" : "error"
    });
  };

  // Toast cleanup
  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  if (loading) return <div className="text-center py-20 text-zinc-400">Loading your collection...</div>;
  if (error) return <div className="text-center py-20 text-red-500">{error}</div>;

  return (
    <div className="min-h-screen bg-zinc-950 py-12 px-4 sm:px-6 lg:px-8">
      <AnimatePresence>
        {toast && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            className={`fixed top-4 left-1/2 -translate-x-1/2 px-6 py-3 rounded-lg ${
              toast.type === "success" ? "bg-green-600" : "bg-red-600"
            } text-white font-medium shadow-lg z-50`}
          >
            {toast.message}
          </motion.div>
        )}
      </AnimatePresence>

      <div className="max-w-7xl mx-auto pt-20">
        <h1 className="text-3xl md:text-4xl font-bold text-center mb-12 text-transparent bg-clip-text bg-gradient-to-r from-red-500 to-amber-500">
          Your Curated Collection
        </h1>

        {wishlistItems.length === 0 ? (
          <div className="text-center py-20">
            <div className="text-zinc-400 text-lg mb-4">Your wishlist is empty</div>
            <Link 
              to="/products" 
              className="inline-block bg-red-600 hover:bg-red-700 text-white px-8 py-3 rounded-full transition-all"
            >
              Explore Products
            </Link>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
            {wishlistItems.map((item, index) => (
              <motion.div 
                key={item._id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.1 }}
                className="group relative bg-zinc-900 rounded-2xl overflow-hidden shadow-2xl hover:shadow-[0_0_30px_rgba(239,68,68,0.2)] transition-all duration-300 cursor-pointer"
                onClick={() => navigate(`/product/${item.product._id}`)}
              >
                <div className="aspect-square overflow-hidden pointer-events-none">
                  <img 
                    src={item.product.image} 
                    alt={item.product.name} 
                    className="w-full h-full object-cover transform transition-transform duration-500 group-hover:scale-110"
                  />
                </div>

                <div className="p-6 pointer-events-none">
                  <h2 className="text-xl font-bold text-white mb-2">{item.product.name}</h2>
                  <p className="text-zinc-400 text-sm mb-4 line-clamp-2">{item.product.description}</p>
                  <p className="text-2xl font-bold text-red-500">${item.product.price.toFixed(2)}</p>
                </div>

                <div className="absolute top-4 right-4 flex gap-2">
                  <button
                    onClick={(e) => handleWishlistToggle(e, item.product._id)}
                    className="w-12 h-12 bg-red-600/80 hover:bg-red-700 rounded-full backdrop-blur-sm flex items-center justify-center transition-all"
                  >
                    <i className="fas fa-heart text-white text-lg"></i>
                  </button>
                  <button
                    onClick={(e) => handleAddToCart(e, item.product)}
                    className="w-12 h-12 bg-green-600/80 hover:bg-green-700 rounded-full backdrop-blur-sm flex items-center justify-center transition-all"
                  >
                    <i className="fas fa-cart-plus text-white text-lg"></i>
                  </button>
                </div>
              </motion.div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Wishlist;
